const items = $input.all();
const d = items[0]?.json || {};
const peers = items.slice(1).map(i => i.json).filter(p => p.peer_ticker);
const meta = typeof d.metadata === 'string' ? JSON.parse(d.metadata) : (d.metadata || {});
const wlMeta = typeof d.wl_meta === 'string' ? JSON.parse(d.wl_meta) : (d.wl_meta || {});

let peerInfo = '';
if (peers.length > 0) {
  peerInfo = '\n\nIndustry Peers:';
  for (const p of peers) peerInfo += `\n- ${p.peer_name} (${p.peer_ticker})${p.on_watchlists?.length ? ' [' + p.on_watchlists.join(', ') + ']' : ''}`;
}

return [{json: {ticker: d.ticker, context: `Analyze short-term trade setup:\nTicker: ${d.ticker} (${d.company_name})\nSector: ${d.sector} | Cap: $${((d.market_cap||0)/1e9).toFixed(1)}B\nSetup: ${d.alert_type?.replace('trade_setup_','')}\nEntry: $${meta.entry} | Target: $${meta.target} | Stop: $${meta.stop}\nConfidence: ${meta.confidence}/10\nRSI: ${wlMeta.rsi} | Beta: ${wlMeta.beta} | Volume: ${wlMeta.volume}${peerInfo}\nDate: ${new Date().toISOString().split('T')[0]}\n\nEvaluate this trade setup. Provide entry, stop-loss, targets, position sizing, holding period, and risk assessment.`}}];
